#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct { float x, y, z; } Vector;
typedef struct { Vector origin, direction; } Ray;
typedef struct { float t; Vector point; Vector normal; int hit; } Hit;
typedef struct { Vector center; float radius; } Sphere;

static Vector vector_create(float x, float y, float z){ Vector v; v.x=x; v.y=y; v.z=z; return v; }
static Vector vector_add(Vector a, Vector b){ return vector_create(a.x+b.x, a.y+b.y, a.z+b.z); }
static Vector vector_subtract(Vector a, Vector b){ return vector_create(a.x-b.x, a.y-b.y, a.z-b.z); }
static Vector vector_multiply(Vector v, float s){ return vector_create(v.x*s, v.y*s, v.z*s); }
static float vector_dot(Vector a, Vector b){ return a.x*b.x + a.y*b.y + a.z*b.z; }
static float vector_length(Vector v){ return sqrtf(v.x*v.x + v.y*v.y + v.z*v.z); }
static Vector vector_normalize(Vector v){ float len = vector_length(v); return vector_create(v.x/len, v.y/len, v.z/len); }

static Hit sphere_intersect(Ray ray, Sphere sphere){
    Hit h; h.hit = 0; h.t = 0; h.point = vector_create(0,0,0); h.normal = vector_create(0,0,0);
    Vector oc = vector_subtract(ray.origin, sphere.center);
    float a = vector_dot(ray.direction, ray.direction);
    float b = 2.0f * vector_dot(oc, ray.direction);
    float c = vector_dot(oc, oc) - sphere.radius * sphere.radius;
    float disc = b*b - 4*a*c;
    if (disc < 0) return h;
    float t1 = (-b - sqrt(disc)) / (2*a);
    float t;
    if (t1 > 0.001f) t = t1;
    else {
        float t2 = (-b + sqrt(disc)) / (2*a);
        if (t2 > 0.001f) t = t2;
        else return h;
    }
    h.hit = 1;
    h.t = t;
    h.point = vector_add(ray.origin, vector_multiply(ray.direction, t));
    h.normal = vector_normalize(vector_subtract(h.point, sphere.center));
    return h;
}

static Vector sky_color(Vector dir){
    float t = 0.5f * (dir.y + 1.0f);
    return vector_create(0.5f*t + (1.0f-t), 0.7f*t + (1.0f-t), 1.0f*t + (1.0f-t));
}

static Vector** allocate_image(int width, int height){
    Vector** img = malloc(height * sizeof(Vector*));
    for (int y = 0; y < height; y++) img[y] = malloc(width * sizeof(Vector));
    return img;
}
static void free_image(Vector** img, int height){
    for (int y = 0; y < height; y++) free(img[y]);
    free(img);
}

static void write_image(const char* filename, Vector** img, int width, int height){
    FILE* fp = fopen(filename, "w");
    if (!fp){ fprintf(stderr, "Error: Could not open file %s for writing\n", filename); return; }
    fprintf(fp, "P3\n%d %d\n255\n", width, height);
    for (int y = 0; y < height; y++){
        for (int x = 0; x < width; x++){
            Vector c = img[y][x];
            int r = (int)((float)fmin(fmax(c.x, 0.0), 1.0) * 255.99f);
            int g = (int)((float)fmin(fmax(c.y, 0.0), 1.0) * 255.99f);
            int b = (int)((float)fmin(fmax(c.z, 0.0), 1.0) * 255.99f);
            fprintf(fp, "%d %d %d\n", r, g, b);
        }
    }
    fclose(fp);
    fprintf(stderr, "Wrote image to %s\n", filename);
}

int main(void){
    int width = 800, height = 600;
    fprintf(stderr, "Creating high-resolution image: %dx%d\n", width, height);
    fprintf(stderr, "This will be downsampled with ffmpeg after rendering\n");

    Vector light = vector_normalize(vector_create(1.0f, 1.0f, -1.0f));
    Sphere sphere; sphere.center = vector_create(0.0f, -0.5f, -5.0f); sphere.radius = 1.0f;
    float plane_y = -1.5f;

    Vector** img = allocate_image(width, height);
    fprintf(stderr, "Rendering high-resolution image...\n");

    for (int y = 0; y < height; y++){
        fprintf(stderr, "\rProgress: %.1f%%", (float)y * 100.0f / 600.0f);
        for (int x = 0; x < width; x++){
            float u = (float)x / 799.0f;
            float v = (float)y / 599.0f;
            Vector d;
            d.x = u * 2.6666667f - 1.3333333f;
            d.y = 2.0f * (1.0f - v) - 1.0f;
            d.z = -1.0f;
            Ray ray; ray.origin = vector_create(0.0f, 0.0f, 0.0f); ray.direction = vector_normalize(d);

            Hit hs = sphere_intersect(ray, sphere);
            int sphit = hs.hit;
            float ts = hs.t;

            int plhit = 0; float tp = 0;
            if (fabsf(ray.direction.y) > 0.0001f){
                tp = (plane_y - ray.origin.y) / ray.direction.y;
                if (tp > 0.001f) plhit = 1;
            }

            Vector color;
            int use_sphere = sphit && (!plhit || ts < tp);
            int use_plane = !use_sphere && plhit;
            if (use_sphere){
                float diff = (float)fmax((double)vector_dot(hs.normal, light), 0.0);
                float L = diff * 0.8f + 0.2f;
                Ray sray; sray.origin = hs.point; sray.direction = light;
                Hit sh = sphere_intersect(sray, sphere);
                if (sh.hit) L = 0.2f;
                color = vector_create(L, 0.2f*L, 0.2f*L);
            } else if (use_plane){
                Vector p = vector_add(ray.origin, vector_multiply(ray.direction, tp));
                int cc = (int)(floor(p.x) + floor(p.z));
                float checker = (cc & 1) ? 0.4f : 0.9f;
                Vector n = vector_create(0.0f, 1.0f, 0.0f);
                float diff = (float)fmax((double)vector_dot(n, light), 0.0);
                float L = diff * 0.8f + 0.2f;
                Ray sray; sray.origin = p; sray.direction = light;
                Hit sh = sphere_intersect(sray, sphere);
                if (sh.hit) L = 0.2f;
                color = vector_create(checker*L, checker*L, checker*L);
            } else {
                color = sky_color(ray.direction);
            }
            img[y][x] = color;
        }
    }
    fprintf(stderr, "\nRendering complete\n");
    write_image("image.ppm", img, width, height);
    free_image(img, height);
    fprintf(stderr, "Done.\n");
    return 0;
}

